package com.agent.tool.engine.api.impl;  import com.agent.tool.engine.api.ToolCallAuditor; import com.agent.tool.engine.model.ToolCallAuditLog; import org.slf4j.Logger; import org.slf4j.LoggerFactory; import org.springframework.stereotype.Component;  import java.util.ArrayList; import java.util.List; import java.util.concurrent.atomic.AtomicLong;  /**  * F8 工具调用审计实现 (tool_call_log 内存持久化)。  *  * <p>骨架阶段使用同步 List 记录审计日志, audit() 自动补全 logId。  * 生产实现应替换为 ClickHouse / Elasticsearch 异步落库。</p>  */ @Component public class ToolCallAuditorImpl implements ToolCallAuditor {      private static final Logger log = LoggerFactory.getLogger(ToolCallAuditorImpl.class);      /** 内存审计日志 (同步访问, 保证线程安全)。 */     private final List<ToolCallAuditLog> logs = new ArrayList<>();     private final AtomicLong idSeq = new AtomicLong(0);      @Override     public void audit(ToolCallAuditLog logEntry) {         if (logEntry == null) {             log.warn("审计收到 null 日志, 跳过");             return;         }         if (logEntry.getLogId() == null || logEntry.getLogId().isBlank()) {             logEntry.setLogId("log-" + idSeq.incrementAndGet());         }         if (logEntry.getOccurredAt() == null) {             logEntry.setOccurredAt(java.time.Instant.now());         }         synchronized (logs) {             logs.add(logEntry);         }         log.debug("审计日志写入: logId={}, traceId={}, toolId={}, status={}",                 logEntry.getLogId(), logEntry.getTraceId(), logEntry.getToolId(), logEntry.getStatus());     }      /** 当前审计日志条数 (供测试 / 监控使用)。 */     public int count() {         synchronized (logs) {             return logs.size();         }     }      /** 返回审计日志副本 (供测试 / 查询使用)。 */     public List<ToolCallAuditLog> allLogs() {         synchronized (logs) {             return new ArrayList<>(logs);         }     } }